actionConfiguration.body:
EXECUTE [dbo].[SER_SEARCH_FOR_PROSPECTS] 
   @PROSPECTS_ID = {{PROSPECT_NUMBER.text||null}}
  ,@USER_TOKEN = {{appsmith.store[Init.userSession]?.TOKEN||null}}
	,@COMPANY_NAME = {{COMPANY_NAME.text == "" || COMPANY_NAME.text == undefined ? null : COMPANY_NAME.text}}
   ,@PROSPECTS_STATUS = {{PROSPECT_STATUS.selectedOptionValue == "" || PROSPECT_STATUS.selectedOptionValue == undefined ? null : PROSPECT_STATUS.selectedOptionValue}}
   ,@TELEPHONE = {{TELEPHONE.text == "" || TELEPHONE.text == undefined ? null : TELEPHONE.text}}
	,@DATE_FROM = {{DATE_FROM.selectedDate == "" || DATE_FROM.selectedDate == undefined ? null : moment(DATE_FROM.formattedDate,Configs.dateFormat).startOf('day')}}
	,@DATE_TO = {{DATE_TO.selectedDate == "" || DATE_TO.selectedDate == undefined ? null : moment(DATE_TO.formattedDate,Configs.dateFormat).endOf('day')}}
